    this.loading = true;
    this.searchTerm = '';
    this.filterStatus = '';
    this.filterPriority = '';
    // Create/Edit
    this.showForm = false;
    this.showDelConfirm = false;
    this.formMode = 'create';
    this.selected = null;
    this.parentTask = null;
    this.editForm = {};
    this.saving = false;
    this.utilizationSummary = '';
    // Lists for dropdowns
    this.projects = [];
    this.departments = [];
    this.teams = [];
    this.skills = [];
    this.filteredTeams = [];
